def transition(state, action):
    s = dict(state)
    name = action.get("name")
    params = action.get("params") or {}

    capacity = s["capacity"]
    cost = s["throttle_cost"] if s["throttled"] else 1

    if name == "request":
        # How many API calls to attempt this step (default 1).
        count = int(params.get("count", 1))
        for _ in range(max(0, count)):
            if s["tokens"] >= cost:
                s["tokens"] -= cost
                s["served"] += 1
            else:
                # Bucket exhausted -> request is rate-limited.
                s["denied"] += 1

    elif name == "refill":
        amount = int(params.get("amount", s["refill_amount"]))
        s["tokens"] = min(capacity, s["tokens"] + max(0, amount))

    elif name == "throttle":
        # Engage / release defensive throttling. An explicit `on` param wins;
        # otherwise toggle the current mode.
        if "on" in params:
            s["throttled"] = bool(params["on"])
        else:
            s["throttled"] = not s["throttled"]

    # Clamp to invariants the contract promises (never negative, never over cap).
    s["tokens"] = max(0, min(capacity, s["tokens"]))
    return s

